const { chromium } = require('/app/node_modules/playwright');
const path = require('path');
const fs = require('fs');

(async () => {
  // Try to find chromium executable
  let executablePath;
  const possiblePaths = [
    '/usr/bin/chromium-browser',
    '/usr/bin/chromium',
    '/usr/bin/google-chrome',
    '/usr/bin/google-chrome-stable',
  ];

  for (const p of possiblePaths) {
    if (fs.existsSync(p)) {
      executablePath = p;
      break;
    }
  }

  console.log('Using executable:', executablePath || 'default playwright chromium');

  const launchOptions = {
    args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-dev-shm-usage'],
    headless: true
  };

  if (executablePath) {
    launchOptions.executablePath = executablePath;
  }

  const browser = await chromium.launch(launchOptions);
  const page = await browser.newPage();
  await page.setViewportSize({ width: 1280, height: 900 });

  // Navigate to the GitLab issue
  await page.goto('http://the-agent-company.com:8929/root/sotopia/-/issues/200', {
    waitUntil: 'networkidle',
    timeout: 60000
  });

  // Wait for the page to fully load
  await page.waitForTimeout(3000);

  // Take a full-page screenshot
  await page.screenshot({
    path: '/workspace/issue_200_screenshot.png',
    fullPage: true
  });

  console.log('Screenshot saved to /workspace/issue_200_screenshot.png');
  await browser.close();
})().catch(err => {
  console.error('Error:', err.message);
  process.exit(1);
});

